/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(CustInvoiceJournal, CustInvoiceJour), FormDataSourceEventType::Activated)]
public static void CustInvoiceJour_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun fr = sender.formRun();

    FormControl falconGasButton = fr.design(0).controlName("ETGSalesInvoiceFalconGas");

    if(curExt() == "N004")
    {
        falconGasButton.visible(true);
    }
    else
    {
        falconGasButton.visible(false);
    }
}
